import type { SyntaxNodeRef } from '@lezer/common';

import { convertFilterStatement } from './statement.js';
import { isDev } from '../../../../../../core/utils/is-node-environment.js';
import { postSpotErrorMark } from '../../../../decorations/decoration-marks.js';
import type { FilterFieldProps } from '../../../../FilterField.types.js';
import type { NumberFormatParser } from '../../../../parser/getNumberParser.js';
import type {
  ConvertedLezerNode,
  FilterFieldFlatGroupNode,
} from '../../../../types/conversion-utils.js';
import type { FilterFieldError } from '../../../../types/filter-field-error.js';
import type {
  FilterFieldErrorNode,
  FilterFieldKeyNode,
  FilterFieldLezerNodeType,
} from '../../../../types/tree-nodes.js';
import type { FilterFieldCustomTypes } from '../../../../types/validation.js';
import type { InternalValidatorMap } from '../../../../utils/validation-utils/normalize-validator-map.js';
import { getColoredSearchOperator } from '../../../validation-utils/validation-helper-functions.js';
import { convertLogicalOperator } from '../logical-operator.js';
import { convertError } from '../value/error.js';

/**
 * Convert a filter field group node.
 * The root 'Filter' node is also handled as group.
 * @internal
 */
export function convertFilterGroup(
  node: SyntaxNodeRef,
  doc: string,
  numberParser: NumberFormatParser,
  internalValidatorMap: InternalValidatorMap | undefined,
  customTypes?: FilterFieldCustomTypes,
  parserConfig?: FilterFieldProps['parserConfig'],
  context?: FilterFieldLezerNodeType,
): ConvertedLezerNode<FilterFieldFlatGroupNode> {
  const { from, to } = node;
  const cursor = node.node.cursor();

  const convertedNode: FilterFieldFlatGroupNode = {
    type: 'Group',
    children: [],
    range: {
      from,
      to,
    },
    explicit: false,
    explicitLogicalOperator: false,
    logicalOperator: 'AND',
  };
  const errors: FilterFieldError[] = [];

  let hasOpeningBracket = false;
  let hasClosingBracket = false;
  let hasChildNodes = false;

  cursor.iterate((childNode) => {
    const childName = childNode.name as FilterFieldLezerNodeType;

    switch (childName) {
      case 'Filter':
        // Intentionally left empty.
        break;
      case 'FilterGroup': {
        // Ignore the group itself, only convert nested groups.
        if (
          node.name !== 'Filter' &&
          childNode.from === from &&
          childNode.to === to
        ) {
          break;
        }

        hasChildNodes = true;
        const { convertedNode: groupNode, errors: groupErrors } =
          convertFilterGroup(
            childNode,
            doc,
            numberParser,
            internalValidatorMap,
            customTypes,
            parserConfig,
            'FilterGroup',
          );
        convertedNode.children.push(groupNode);
        errors.push(...groupErrors);

        return false;
      }
      case 'FilterStatement': {
        hasChildNodes = true;
        const { convertedNode: statementNode, errors: statementErrors } =
          convertFilterStatement(
            childNode,
            doc,
            numberParser,
            internalValidatorMap,
            customTypes,
            parserConfig,
            context,
          );
        convertedNode.children.push(statementNode);
        errors.push(...statementErrors);

        return false;
      }
      case 'LogicalOperator': {
        hasChildNodes = true;
        const { convertedNode: operatorNode, errors: logicalOperatorErrors } =
          convertLogicalOperator(childNode, doc);

        if (logicalOperatorErrors.length > 0) {
          // A logical operator error should be wrapped in a statement so that the 'replace-statement'
          // insertion strategy still works properly with the cursor positioned in the error node.
          convertedNode.children.push({
            type: 'Statement',
            range: operatorNode.range,
            key: operatorNode as FilterFieldKeyNode,
          });
        } else {
          convertedNode.children.push(operatorNode);
        }
        errors.push(...logicalOperatorErrors);

        return false;
      }
      case 'OpeningBracket':
        if (node.name !== 'Filter') {
          hasOpeningBracket = true;
          convertedNode.explicit = true;
        }
        break;
      case 'ClosingBracket':
        if (node.name !== 'Filter') {
          hasClosingBracket = true;
          convertedNode.explicit = true;
        }
        break;
      case '⚠':
        if (node.name === 'Filter') {
          if (childNode.node.firstChild) {
            const { convertedNode: errorNode } = convertError(
              cursor,
              childNode,
              doc,
            );
            convertedNode.children.push(errorNode);
            errors.push({
              range: errorNode.range,
              message: 'incompleteGroupError',
            });
          } else {
            const { convertedNode: errorNode } = convertError(
              cursor,
              childNode,
              doc,
            );
            convertedNode.children.push(errorNode);

            // eslint-disable-next-line @typescript-eslint/no-deprecated
            if (parserConfig?.searchConversion) {
              errors.push({
                range: errorNode.range,
                message: {
                  type: 'incompleteStatementWithEnabledSearchError',
                  details: getColoredSearchOperator(),
                },
              });
            } else {
              errors.push({
                range: errorNode.range,
                message: 'incompleteStatementError',
              });
            }
          }
        }
        return false;
      default:
        if (isDev()) {
          // eslint-disable-next-line no-console
          console.log(
            `${doc.toString()} | Syntax node '${childName}' cannot be converted. Please make sure to handle all nodes accordingly.`,
          );
        }
    }
  });

  const groupError: FilterFieldErrorNode = {
    type: 'Error',
    range: { from, to },
    value: '',
    textValue: '',
  };

  // Only opening and closing bracket -> empty filter group error.
  const emptyBracketGroup =
    hasOpeningBracket && hasClosingBracket && !hasChildNodes;

  if (emptyBracketGroup) {
    groupError.range = { from: from + 1, to: to - 1 };
    convertedNode.children.push(groupError);

    errors.push({
      range: { from, to },
      message: 'emptyGroupError',
    });
  } else if (hasOpeningBracket && !hasClosingBracket) {
    groupError.range = { from: to, to };
    convertedNode.children.push(groupError);
    errors.push({
      range: { from: to - 1, to },
      message: 'incompleteGroupError',
      decoration: postSpotErrorMark,
    });
  }

  return { convertedNode, errors };
}
